mapper.update:
    UPDATE tb_bom_mst
    SET  item_cd 	    = #{itemCd}
        ,client_id  	= #{clientId}
        ,manager_id  	= #{managerId}
        ,lab_no 	    = #{labNo}
        ,prod_type	    = #{prodType}
        ,usage 	        = #{usage}
        ,caution 	    = #{caution}
        ,note 	        = #{note}
        ,significant 	= #{significant}
        ,qty 	        = isnull(#{qty}, 0)
        ,approval_state = #{approvalState}
        ,etc 	        = #{etc}
        ,upd_id         = #{userId}
        ,upd_dt         = getdate()
where   bom_id = #{bomId}

